 31→/**
 32→ * Appends a Unicode date/time format string to the [DateTimeFormatBuilder].
 33→ *
 34→ * This is the format string syntax used by the Java Time's `DateTimeFormatter` class, Swift's and Objective-C's
 35→ * `NSDateFormatter` class, and the ICU library.
 36→ * The syntax is specified at
 37→ * <https://unicode-org.github.io/icu/userguide/format_parse/datetime/#datetime-format-syntax>.
 38→ *
 39→ * Currently, locale-aware directives are not supported, due to no locale support in Kotlin.
 40→ *
 41→ * In addition to the standard syntax, this function also supports the following extensions:
 42→ * * `[]` denote optional sections. For example, `hh:mm[:ss]` will allow parsing seconds optionally.
 43→ *   This is similar to what is supported by the Java Time's `DateTimeFormatter` class.
 44→ *
 45→ * Usage example:
 46→ * ```
 47→ * DateTimeComponents.Format {
 48→ *   // 2023-01-20T23:53:16.312+03:30[Asia/Tehran]
 49→ *   byUnicodePattern("uuuu-MM-dd'T'HH:mm[:ss[.SSS]]xxxxx'['VV']'")
 50→ * }
 51→ * ```
 52→ *
 53→ * The list of supported directives is as follows:
 54→ *
 55→ * | **Directive**       | **Meaning**                                                                             |
 56→ * | `'string'`          | literal `string`, without quotes                                                        |
 57→ * | `'''`               | literal char `'`                                                                        |
 58→ * | `[fmt]`             | equivalent to `fmt` during formatting, but during parsing also accepts the empty string |
 59→ * | `u`                 | ISO year without padding                                                                |
 60→ * | `uu`                | last two digits of the ISO year, with the base year 2000                                |
 61→ * | `uuuu`              | ISO year, zero-padded to four digits                                                    |
 62→ * | `M`, `L`            | month number (1-12), without padding                                                    |
 63→ * | `MM`, `LL`          | month number (01-12), zero-padded to two digits                                         |
 64→ * | `d`                 | day-of-month (1-31), without padding                                                    |
 65→ * | `H`                 | hour-of-day (0-23), without padding                                                     |
 66→ * | `HH`                | hour-of-day (00-23), zero-padded to two digits                                          |
 67→ * | `m`                 | minute-of-hour (0-59), without padding                                                  |
 68→ * | `mm`                | minute-of-hour (00-59), zero-padded to two digits                                       |
 69→ * | `s`                 | second-of-hour (0-59), without padding                                                  |
 70→ * | `ss`                | second-of-hour (00-59), zero-padded to two digits                                       |
 71→ * | `S`, `SS`, `SSS`... | fraction-of-second without a leading dot, with as many digits as the format length      |
 72→ * | `VV`                | timezone name (for example, `Europe/Berlin`)                                            |
 73→ *
 74→ * The UTC offset is formatted using one of the following directives. In every one of these formats, hours, minutes,
 75→ * and seconds are zero-padded to two digits. Also, hours are unconditionally present.
 76→ * 
 77→ * | **Directive**          | **Minutes** | **Seconds** | **Separator** | **Representation of zero** |
 78→ * | `X`                    | unless zero | never       | none          | `Z`                        |
 79→ * | `XX`                   | always      | never       | none          | `Z`                        |
 80→ * | `XXX`                  | always      | never       | colon         | `Z`                        |
 81→ * | `XXXX`                 | always      | unless zero | none          | `Z`                        |
 82→ * | `XXXXX`, `ZZZZZ`       | always      | unless zero | colon         | `Z`                        |
 83→ * | `x`                    | unless zero | never       | none          | `+00`                      |
 84→ * | `xx`, `Z`, `ZZ`, `ZZZ` | always      | never       | none          | `+0000`                    |
 85→ * | `xxx`                  | always      | never       | colon         | `+00:00`                   |
 86→ * | `xxxx`                 | always      | unless zero | none          | `+0000`                    |
 87→ * | `xxxxx`                | always      | unless zero | colon         | `+00:00`                   |
 88→ *
 89→ * Additionally, because the `y` directive is very often used instead of `u`, they are taken to mean the same.
 90→ * This may lead to unexpected results if the year is negative: `y` would always produce a positive number, whereas
 91→ * `u` may sometimes produce a negative one. For example:
 92→ * ```
 93→ * LocalDate(-10, 1, 5).format { byUnicodeFormat("yyyy-MM-dd") } // -0010-01-05
 94→ * LocalDate(-10, 1, 5).toJavaLocalDate().format(java.time.format.DateTimeFormatter.ofPattern("yyyy-MM-dd")) // 0011-01-05
 95→ * ```
 96→ *
 97→ * Note that, when the format includes the era directive, [byUnicodePattern] will fail with an exception, so almost all
 98→ * of the intentional usages of `y` will correctly report an error instead of behaving slightly differently.
 99→ *
100→ * @throws IllegalArgumentException if the pattern is invalid or contains unsupported directives.
101→ * @throws IllegalArgumentException if the builder is incompatible with the specified directives.
102→ * @throws UnsupportedOperationException if the kotlinx-datetime library does not support the specified directives.
103→ */
104→@FormatStringsInDatetimeFormats
105→public fun DateTimeFormatBuilder.byUnicodePattern(pattern: String) {
106→    val directives = UnicodeFormat.parse(pattern)
107→    fun rec(builder: DateTimeFormatBuilder, format: UnicodeFormat) {
108→        when (format) {
109→            is UnicodeFormat.StringLiteral -> builder.chars(format.literal)
110→            is UnicodeFormat.Sequence -> format.formats.forEach { rec(builder, it) }
111→            is UnicodeFormat.OptionalGroup -> builder.alternativeParsing({}) {
112→                rec(this, format.format)
113→            }
114→            is UnicodeFormat.Directive -> {
115→                when (format) {
116→                    is UnicodeFormat.Directive.TimeBased -> {
117→                        require(builder is DateTimeFormatBuilder.WithTime) {
118→                            "A time-based directive $format was used in a format builder that doesn't support time components"
119→                        }
120→                        format.addToFormat(builder)
121→                    }
122→
123→                    is UnicodeFormat.Directive.DateBased -> {
124→                        require(builder is DateTimeFormatBuilder.WithDate) {
125→                            "A date-based directive $format was used in a format builder that doesn't support date components"
126→                        }
127→                        format.addToFormat(builder)
128→                    }
129→
130→                    is UnicodeFormat.Directive.ZoneBased -> {
131→                        require(builder is DateTimeFormatBuilder.WithDateTimeComponents) {
132→                            "A time-zone-based directive $format was used in a format builder that doesn't support time-zone components"
133→                        }
134→                        format.addToFormat(builder)
135→                    }
136→
137→                    is UnicodeFormat.Directive.OffsetBased -> {
138→                        require(builder is DateTimeFormatBuilder.WithUtcOffset) {
139→                            "A UTC-offset-based directive $format was used in a format builder that doesn't support UTC offset components"
140→                        }
141→                        format.addToFormat(builder)
142→                    }
143→
144→                    is UnknownUnicodeDirective -> {
145→                        throw IllegalArgumentException("The meaning of the directive '$format' is unknown")
146→                    }
147→                }
148→            }
149→        }
150→    }
151→    rec(this, directives)
152→}
