159→internal sealed interface UnicodeFormat {
160→    companion object {
161→        fun parse(pattern: String): UnicodeFormat {
162→            val groups: MutableList<MutableList<UnicodeFormat>?> = mutableListOf(mutableListOf())
163→            var insideLiteral = false
164→            var literal = ""
165→            var lastCharacter: Char? = null
166→            var lastCharacterCount = 0
167→            for (character in pattern) {
168→                if (character == lastCharacter) {
169→                    ++lastCharacterCount
170→                } else if (insideLiteral) {
171→                    if (character == '\'') {
172→                        groups.last()?.add(StringLiteral(literal.ifEmpty { "'" }))
173→                        insideLiteral = false
174→                        literal = ""
175→                    } else literal += character
176→                } else {
177→                    if (lastCharacterCount > 0) {
178→                        groups.last()?.add(unicodeDirective(lastCharacter!!, lastCharacterCount))
179→                        lastCharacter = null
180→                        lastCharacterCount = 0
181→                    }
182→                    if (character !in nonPlainCharacters) {
183→                        literal += character
184→                        continue
185→                    }
186→                    if (literal != "") {
187→                        groups.last()?.add(StringLiteral(literal))
188→                        literal = ""
189→                    }
190→                    when (character) {
191→                        '\'' -> {
192→                            insideLiteral = true
193→                            literal = ""
194→                        }
195→
196→                        '[' -> {
197→                            groups.add(mutableListOf())
198→                        }
199→
200→                        ']' -> {
201→                            val group =
202→                                groups.removeLast() ?: throw IllegalArgumentException("Unmatched closing bracket")
203→                            groups.last()?.add(OptionalGroup(Sequence(group)))
204→                        }
205→
206→                        else -> {
207→                            lastCharacter = character
208→                            lastCharacterCount = 1
209→                        }
210→                    }
211→                }
212→            }
213→            if (lastCharacterCount > 0) {
214→                groups.last()?.add(unicodeDirective(lastCharacter!!, lastCharacterCount))
215→            }
216→            if (literal != "") {
217→                groups.last()?.add(StringLiteral(literal))
218→            }
219→            return Sequence(groups.removeLast() ?: throw IllegalArgumentException("Unmatched opening bracket"))
220→        }
221→    }
