575→private fun unicodeDirective(char: Char, formatLength: Int): UnicodeFormat = when (char) {
576→    'G' -> UnicodeFormat.Directive.DateBased.Era(formatLength)
577→    'y' -> UnicodeFormat.Directive.DateBased.YearOfEra(formatLength)
578→    'Y' -> UnicodeFormat.Directive.DateBased.WeekBasedYear(formatLength)
579→    'u' -> UnicodeFormat.Directive.DateBased.Year(formatLength)
580→    'U' -> UnicodeFormat.Directive.DateBased.CyclicYearName(formatLength)
581→    'r' -> UnicodeFormat.Directive.DateBased.RelatedGregorianYear(formatLength)
582→    'Q' -> UnicodeFormat.Directive.DateBased.QuarterOfYear(formatLength)
583→    'q' -> UnicodeFormat.Directive.DateBased.StandaloneQuarterOfYear(formatLength)
584→    'M' -> UnicodeFormat.Directive.DateBased.MonthOfYear(formatLength)
585→    'L' -> UnicodeFormat.Directive.DateBased.StandaloneMonthOfYear(formatLength)
586→    'w' -> UnicodeFormat.Directive.DateBased.WeekOfWeekBasedYear(formatLength)
587→    'W' -> UnicodeFormat.Directive.DateBased.WeekOfMonth(formatLength)
588→    'd' -> UnicodeFormat.Directive.DateBased.DayOfMonth(formatLength)
589→    'D' -> UnicodeFormat.Directive.DateBased.DayOfYear(formatLength)
590→    'F' -> UnicodeFormat.Directive.DateBased.DayOfWeekInMonth(formatLength)
591→    'g' -> UnicodeFormat.Directive.DateBased.ModifiedJulianDay(formatLength)
592→    'E' -> UnicodeFormat.Directive.DateBased.DayOfWeek(formatLength)
593→    'e' -> UnicodeFormat.Directive.DateBased.LocalizedDayOfWeek(formatLength)
594→    'c' -> UnicodeFormat.Directive.DateBased.StandaloneLocalizedDayOfWeek(formatLength)
595→    'a' -> UnicodeFormat.Directive.TimeBased.AmPmMarker(formatLength)
596→    'h' -> UnicodeFormat.Directive.TimeBased.AmPmHourOfDay(formatLength)
597→    'H' -> UnicodeFormat.Directive.TimeBased.HourOfDay(formatLength)
598→    'm' -> UnicodeFormat.Directive.TimeBased.MinuteOfHour(formatLength)
599→    's' -> UnicodeFormat.Directive.TimeBased.WithSecondPrecision.SecondOfMinute(formatLength)
600→    'S' -> UnicodeFormat.Directive.TimeBased.WithSubsecondPrecision.FractionOfSecond(formatLength)
601→    'A' -> UnicodeFormat.Directive.TimeBased.WithSubsecondPrecision.MilliOfDay(formatLength)
602→    'n' -> UnicodeFormat.Directive.TimeBased.WithSubsecondPrecision.NanoOfSecond(formatLength)
603→    'N' -> UnicodeFormat.Directive.TimeBased.WithSubsecondPrecision.NanoOfDay(formatLength)
604→    'V' -> UnicodeFormat.Directive.ZoneBased.TimeZoneId(formatLength)
605→    'v' -> UnicodeFormat.Directive.ZoneBased.GenericTimeZoneName(formatLength)
606→    'z' -> UnicodeFormat.Directive.ZoneBased.TimeZoneName(formatLength)
607→    'O' -> UnicodeFormat.Directive.OffsetBased.LocalizedZoneOffset(formatLength)
608→    'X' -> UnicodeFormat.Directive.OffsetBased.ZoneOffset1(formatLength)
609→    'x' -> UnicodeFormat.Directive.OffsetBased.ZoneOffset2(formatLength)
610→    'Z' -> UnicodeFormat.Directive.OffsetBased.ZoneOffset3(formatLength)
611→    else -> UnknownUnicodeDirective(char, formatLength)
612→}
